/*
 * test-common.h -- Shared macros for libm accuracy tests
 *
 * Standalone tests (not using picolibc's meson test framework).
 * Each test file includes this header and golden-values.h.
 */
#ifndef TEST_COMMON_H
#define TEST_COMMON_H

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <stdint.h>
#include <string.h>
#include <float.h>
#include <fenv.h>

/* --- Bit-level helpers --- */

static inline uint64_t double_to_bits(double x)
{
    uint64_t u;
    memcpy(&u, &x, sizeof(u));
    return u;
}

static inline double bits_to_double(uint64_t u)
{
    double x;
    memcpy(&x, &u, sizeof(x));
    return x;
}

static inline uint32_t float_to_bits(float x)
{
    uint32_t u;
    memcpy(&u, &x, sizeof(u));
    return u;
}

static inline float bits_to_float(uint32_t u)
{
    float x;
    memcpy(&x, &u, sizeof(x));
    return x;
}

/* --- ULP distance --- */

static inline uint64_t ulp_distance_double(double a, double b)
{
    /* Handle NaN: if either is NaN, return UINT64_MAX */
    if (isnan(a) || isnan(b))
        return UINT64_MAX;

    /* Handle exact equality (including +0 == -0) */
    if (a == b)
        return 0;

    uint64_t ua = double_to_bits(a);
    uint64_t ub = double_to_bits(b);

    /* If signs differ, sum distances to zero */
    if ((ua >> 63) != (ub >> 63)) {
        /* Distance from a to 0 plus distance from b to 0 */
        uint64_t da = ua & 0x7FFFFFFFFFFFFFFFULL;
        uint64_t db = ub & 0x7FFFFFFFFFFFFFFFULL;
        return da + db;
    }

    /* Same sign: simple difference of bit patterns */
    if (ua > ub)
        return ua - ub;
    return ub - ua;
}

static inline uint32_t ulp_distance_float(float a, float b)
{
    if (isnan(a) || isnan(b))
        return UINT32_MAX;

    if (a == b)
        return 0;

    uint32_t ua = float_to_bits(a);
    uint32_t ub = float_to_bits(b);

    if ((ua >> 31) != (ub >> 31)) {
        uint32_t da = ua & 0x7FFFFFFFU;
        uint32_t db = ub & 0x7FFFFFFFU;
        return da + db;
    }

    if (ua > ub)
        return ua - ub;
    return ub - ua;
}

/* --- Test counters --- */

static int test_pass_count = 0;
static int test_fail_count = 0;

/* --- CHECK macros --- */

#define CHECK_DOUBLE(func_name, func_call, input_str, expected, max_ulp) \
    do { \
        double _got = (func_call); \
        uint64_t _ulp = ulp_distance_double(_got, (expected)); \
        if (_ulp <= (uint64_t)(max_ulp)) { \
            test_pass_count++; \
        } else { \
            test_fail_count++; \
            printf("FAIL: %s(%s) = %.17g, expected %.17g, ULP=%llu (max %llu)\n", \
                   func_name, input_str, _got, (double)(expected), \
                   (unsigned long long)_ulp, (unsigned long long)(max_ulp)); \
        } \
    } while (0)

#define CHECK_FLOAT(func_name, func_call, input_str, expected, max_ulp) \
    do { \
        float _got = (func_call); \
        uint32_t _ulp = ulp_distance_float(_got, (expected)); \
        if (_ulp <= (uint32_t)(max_ulp)) { \
            test_pass_count++; \
        } else { \
            test_fail_count++; \
            printf("FAIL: %s(%s) = %.9g, expected %.9g, ULP=%u (max %u)\n", \
                   func_name, input_str, (double)_got, (double)(expected), \
                   (unsigned)_ulp, (unsigned)(max_ulp)); \
