        } else { \
            test_fail_count++; \
            printf("FAIL: %s(%s) = %.17g, expected NaN\n", \
                   func_name, input_str, _got); \
        } \
    } while (0)

#define CHECK_FLOAT_NAN(func_name, func_call, input_str) \
