            test_pass_count++; \
        } else { \
            test_fail_count++; \
            printf("FAIL: %s(%s) = %.9g, expected NaN\n", \
                   func_name, input_str, (double)_got); \
        } \
    } while (0)

#define CHECK_DOUBLE_INF(func_name, func_call, input_str, expected_sign) \
    do { \
