/*
 * test-sin.c -- Accuracy test for sin() and sinf()
 */
#include "test-common.h"
#include "golden-values.h"

static void test_sin_golden(void)
{
    for (unsigned i = 0; i < GOLDEN_SIN_COUNT; i++) {
        char buf[64];
        snprintf(buf, sizeof(buf), "%.17g", golden_sin[i].input);
        CHECK_DOUBLE("sin", sin(golden_sin[i].input), buf,
                     golden_sin[i].expected, golden_sin[i].max_ulp);
    }
}

static void test_sin_special(void)
{
    /* sin(+0) = +0 */
    CHECK_DOUBLE("sin", sin(0.0), "0.0", 0.0, 0);
    /* sin(-0) = -0 */
    CHECK_DOUBLE("sin", sin(-0.0), "-0.0", -0.0, 0);
    /* sin(Inf) = NaN */
    CHECK_DOUBLE_NAN("sin", sin(INFINITY), "Inf");
    CHECK_DOUBLE_NAN("sin", sin(-INFINITY), "-Inf");
    /* sin(NaN) = NaN */
    CHECK_DOUBLE_NAN("sin", sin(NAN), "NaN");
}

static void test_sinf_golden(void)
{
    for (unsigned i = 0; i < GOLDEN_SINF_COUNT; i++) {
        char buf[64];
        snprintf(buf, sizeof(buf), "%.9g", (double)golden_sinf[i].input);
        CHECK_FLOAT("sinf", sinf(golden_sinf[i].input), buf,
                    golden_sinf[i].expected, golden_sinf[i].max_ulp);
    }
}

static void test_sinf_special(void)
{
    CHECK_FLOAT("sinf", sinf(0.0f), "0.0f", 0.0f, 0);
    CHECK_FLOAT("sinf", sinf(-0.0f), "-0.0f", -0.0f, 0);
    CHECK_FLOAT_NAN("sinf", sinf(INFINITY), "Inf");
    CHECK_FLOAT_NAN("sinf", sinf(-INFINITY), "-Inf");
    CHECK_FLOAT_NAN("sinf", sinf(NAN), "NaN");
}

int main(void)
{
    printf("=== sin/sinf accuracy test ===\n");

    test_sin_golden();
    test_sin_special();
    test_sinf_golden();
    test_sinf_special();

    TEST_SUMMARY("sin/sinf");
}

