    CHECK_DOUBLE2("copysign", copysign(INFINITY, -1.0), "Inf, -1.0", -INFINITY, 0);
    CHECK_DOUBLE2("copysign", copysign(-INFINITY, 1.0), "-Inf, 1.0", INFINITY, 0);
    /* copysign with NaN: result has magnitude of first arg, sign of second */
    CHECK_DOUBLE2("copysign", copysign(3.14, -0.0), "3.14, -0.0", -3.14, 0);

    /* Check that copysign(NaN, -1) gives a negative NaN */
    {
        double r = copysign(NAN, -1.0);
        if (isnan(r) && signbit(r)) {
            test_pass_count++;
        } else {
            test_fail_count++;
            printf("FAIL: copysign(NaN, -1.0) should be -NaN\n");
        }
    }

    /* --- copysignf (float) --- */
    CHECK_FLOAT2("copysignf", copysignf(1.0f, 1.0f), "1.0f, 1.0f", 1.0f, 0);
