    CHECK_FLOAT2("copysignf", copysignf(-1.0f, 1.0f), "-1.0f, 1.0f", 1.0f, 0);
    CHECK_FLOAT2("copysignf", copysignf(0.0f, -1.0f), "0.0f, -1.0f", -0.0f, 0);
    CHECK_FLOAT2("copysignf", copysignf(-0.0f, 1.0f), "-0.0f, 1.0f", 0.0f, 0);
    CHECK_FLOAT2("copysignf", copysignf(INFINITY, -1.0f), "Inf, -1.0f", -INFINITY, 0);

    {
        float r = copysignf(NAN, -1.0f);
        if (isnan(r) && signbit(r)) {
            test_pass_count++;
        } else {
            test_fail_count++;
            printf("FAIL: copysignf(NaN, -1.0f) should be -NaN\n");
        }
    }

    TEST_SUMMARY("copysign/copysignf");
}

