/*
 * test-round.c -- Accuracy test for rounding-to-integer functions:
 *   lrint/lrintf, llrint/llrintf, lround/lroundf, llround/llroundf
 */
#include "test-common.h"

int main(void)
{
    printf("=== round accuracy test ===\n");

    /* ---- lrint (double) ---- */
    /* Default rounding mode is round-to-nearest-even */
    CHECK_INT("lrint", lrint(0.0), "0.0", 0);
    CHECK_INT("lrint", lrint(-0.0), "-0.0", 0);
    CHECK_INT("lrint", lrint(1.0), "1.0", 1);
    CHECK_INT("lrint", lrint(-1.0), "-1.0", -1);
    CHECK_INT("lrint", lrint(1.4), "1.4", 1);
    CHECK_INT("lrint", lrint(1.5), "1.5", 2);    /* round to even */
    CHECK_INT("lrint", lrint(2.5), "2.5", 2);    /* round to even */
    CHECK_INT("lrint", lrint(1.6), "1.6", 2);
    CHECK_INT("lrint", lrint(-1.5), "-1.5", -2); /* round to even */
    CHECK_INT("lrint", lrint(-2.5), "-2.5", -2); /* round to even */
    CHECK_INT("lrint", lrint(100.0), "100.0", 100);
    CHECK_INT("lrint", lrint(0.49999999999999994), "0.49999...", 0);
    CHECK_INT("lrint", lrint(3.5), "3.5", 4);
    CHECK_INT("lrint", lrint(4.5), "4.5", 4);    /* round to even */

    /* ---- lrintf (float) ---- */
    CHECK_INT("lrintf", lrintf(0.0f), "0.0f", 0);
    CHECK_INT("lrintf", lrintf(1.0f), "1.0f", 1);
    CHECK_INT("lrintf", lrintf(1.4f), "1.4f", 1);
    CHECK_INT("lrintf", lrintf(1.5f), "1.5f", 2);
    CHECK_INT("lrintf", lrintf(2.5f), "2.5f", 2);
    CHECK_INT("lrintf", lrintf(-1.5f), "-1.5f", -2);
    CHECK_INT("lrintf", lrintf(100.0f), "100.0f", 100);

    /* ---- llrint (double) ---- */
    CHECK_INT("llrint", llrint(0.0), "0.0", 0);
    CHECK_INT("llrint", llrint(1.0), "1.0", 1);
    CHECK_INT("llrint", llrint(1.5), "1.5", 2);
    CHECK_INT("llrint", llrint(2.5), "2.5", 2);
    CHECK_INT("llrint", llrint(-1.5), "-1.5", -2);
    CHECK_INT("llrint", llrint(1e15), "1e15", 1000000000000000LL);

    /* ---- llrintf (float) ---- */
    CHECK_INT("llrintf", llrintf(0.0f), "0.0f", 0);
    CHECK_INT("llrintf", llrintf(1.5f), "1.5f", 2);
    CHECK_INT("llrintf", llrintf(2.5f), "2.5f", 2);

    /* ---- lround (double) ---- */
    /* lround: ties go away from zero */
    CHECK_INT("lround", lround(0.0), "0.0", 0);
    CHECK_INT("lround", lround(1.0), "1.0", 1);
    CHECK_INT("lround", lround(-1.0), "-1.0", -1);
    CHECK_INT("lround", lround(1.4), "1.4", 1);
    CHECK_INT("lround", lround(1.5), "1.5", 2);   /* away from zero */
    CHECK_INT("lround", lround(2.5), "2.5", 3);   /* away from zero */
    CHECK_INT("lround", lround(-1.5), "-1.5", -2);
    CHECK_INT("lround", lround(-2.5), "-2.5", -3);
    CHECK_INT("lround", lround(1.6), "1.6", 2);

    /* ---- lroundf (float) ---- */
    CHECK_INT("lroundf", lroundf(0.0f), "0.0f", 0);
    CHECK_INT("lroundf", lroundf(1.5f), "1.5f", 2);
    CHECK_INT("lroundf", lroundf(2.5f), "2.5f", 3);
    CHECK_INT("lroundf", lroundf(-1.5f), "-1.5f", -2);

    /* ---- llround (double) ---- */
    CHECK_INT("llround", llround(0.0), "0.0", 0);
    CHECK_INT("llround", llround(1.5), "1.5", 2);
    CHECK_INT("llround", llround(2.5), "2.5", 3);
    CHECK_INT("llround", llround(-1.5), "-1.5", -2);
    CHECK_INT("llround", llround(1e15), "1e15", 1000000000000000LL);

    /* ---- llroundf (float) ---- */
    CHECK_INT("llroundf", llroundf(0.0f), "0.0f", 0);
    CHECK_INT("llroundf", llroundf(1.5f), "1.5f", 2);
    CHECK_INT("llroundf", llroundf(2.5f), "2.5f", 3);

    TEST_SUMMARY("round");
}

