        sincos(golden_cos[i].input, &s, &c);
        CHECK_DOUBLE("sincos:cos", c, buf,
                     golden_cos[i].expected, golden_cos[i].max_ulp);
    }
}

static void test_sincos_special(void)
{
    double s, c;

    sincos(0.0, &s, &c);
    CHECK_DOUBLE("sincos:sin", s, "0.0", 0.0, 0);
    CHECK_DOUBLE("sincos:cos", c, "0.0", 1.0, 0);

    sincos(-0.0, &s, &c);
    CHECK_DOUBLE("sincos:sin", s, "-0.0", -0.0, 0);
    CHECK_DOUBLE("sincos:cos", c, "-0.0", 1.0, 0);

