/*
 * test-sqrt.c -- Accuracy test for sqrt() and sqrtf()
 *
 * IEEE 754 requires sqrt to be correctly rounded (0 ULP).
 */
#include "test-common.h"
#include "golden-values.h"

static void test_sqrt_golden(void)
{
    for (unsigned i = 0; i < GOLDEN_SQRT_COUNT; i++) {
        char buf[64];
        snprintf(buf, sizeof(buf), "%.17g", golden_sqrt[i].input);
        CHECK_DOUBLE("sqrt", sqrt(golden_sqrt[i].input), buf,
                     golden_sqrt[i].expected, golden_sqrt[i].max_ulp);
    }
}

static void test_sqrt_special(void)
{
    CHECK_DOUBLE("sqrt", sqrt(0.0), "0.0", 0.0, 0);
    CHECK_DOUBLE("sqrt", sqrt(-0.0), "-0.0", -0.0, 0);
    CHECK_DOUBLE_INF("sqrt", sqrt(INFINITY), "Inf", +1);
    CHECK_DOUBLE_NAN("sqrt", sqrt(-1.0), "-1.0");
    CHECK_DOUBLE_NAN("sqrt", sqrt(-INFINITY), "-Inf");
    CHECK_DOUBLE_NAN("sqrt", sqrt(NAN), "NaN");
}

static void test_sqrtf_golden(void)
{
    for (unsigned i = 0; i < GOLDEN_SQRTF_COUNT; i++) {
        char buf[64];
        snprintf(buf, sizeof(buf), "%.9g", (double)golden_sqrtf[i].input);
        CHECK_FLOAT("sqrtf", sqrtf(golden_sqrtf[i].input), buf,
                    golden_sqrtf[i].expected, golden_sqrtf[i].max_ulp);
    }
}

static void test_sqrtf_special(void)
{
    CHECK_FLOAT("sqrtf", sqrtf(0.0f), "0.0f", 0.0f, 0);
    CHECK_FLOAT("sqrtf", sqrtf(-0.0f), "-0.0f", -0.0f, 0);
    CHECK_FLOAT_INF("sqrtf", sqrtf(INFINITY), "Inf", +1);
    CHECK_FLOAT_NAN("sqrtf", sqrtf(-1.0f), "-1.0f");
    CHECK_FLOAT_NAN("sqrtf", sqrtf(NAN), "NaN");
}

int main(void)
{
    printf("=== sqrt/sqrtf accuracy test ===\n");

    test_sqrt_golden();
    test_sqrt_special();
    test_sqrtf_golden();
    test_sqrtf_special();

    TEST_SUMMARY("sqrt/sqrtf");
}

/*
 * test-fma.c -- Accuracy test for fma() and fmaf()
 *
 * IEEE 754 requires fma to be correctly rounded (0 ULP).
 */
#include "test-common.h"
#include "golden-values.h"

static void test_fma_golden(void)
{
    for (unsigned i = 0; i < GOLDEN_FMA_COUNT; i++) {
        char buf[128];
        snprintf(buf, sizeof(buf), "%.17g, %.17g, %.17g",
                 golden_fma[i].in1, golden_fma[i].in2, golden_fma[i].in3);
        CHECK_DOUBLE("fma", fma(golden_fma[i].in1, golden_fma[i].in2, golden_fma[i].in3),
                     buf, golden_fma[i].expected, golden_fma[i].max_ulp);
    }
}

static void test_fma_special(void)
{
    /* fma(0, inf, nan) etc. -- implementation-defined but should not crash */
    CHECK_DOUBLE_NAN("fma", fma(0.0, INFINITY, NAN), "0, Inf, NaN");
    CHECK_DOUBLE_NAN("fma", fma(NAN, 1.0, 1.0), "NaN, 1, 1");

    /* Basic identity: fma(a, 1, 0) = a */
    CHECK_DOUBLE("fma", fma(3.14, 1.0, 0.0), "3.14, 1, 0", 3.14, 0);
    /* fma(a, 0, c) = c */
    CHECK_DOUBLE("fma", fma(3.14, 0.0, 2.72), "3.14, 0, 2.72", 2.72, 0);
}

static void test_fmaf_golden(void)
{
    for (unsigned i = 0; i < GOLDEN_FMAF_COUNT; i++) {
        char buf[128];
        snprintf(buf, sizeof(buf), "%.9g, %.9g, %.9g",
                 (double)golden_fmaf[i].in1, (double)golden_fmaf[i].in2,
                 (double)golden_fmaf[i].in3);
        CHECK_FLOAT("fmaf", fmaf(golden_fmaf[i].in1, golden_fmaf[i].in2, golden_fmaf[i].in3),
                    buf, golden_fmaf[i].expected, golden_fmaf[i].max_ulp);
    }
}

static void test_fmaf_special(void)
{
    CHECK_FLOAT_NAN("fmaf", fmaf(NAN, 1.0f, 1.0f), "NaN, 1, 1");
    CHECK_FLOAT("fmaf", fmaf(3.14f, 1.0f, 0.0f), "3.14f, 1, 0", 3.14f, 0);
    CHECK_FLOAT("fmaf", fmaf(3.14f, 0.0f, 2.72f), "3.14f, 0, 2.72f", 2.72f, 0);
}

int main(void)
{
    printf("=== fma/fmaf accuracy test ===\n");

    test_fma_golden();
    test_fma_special();
    test_fmaf_golden();
    test_fmaf_special();

    TEST_SUMMARY("fma/fmaf");
}

