{
    printf("=== fmax/fmin/fmaxf/fminf accuracy test ===\n");

    /* --- fmax (double) --- */
    CHECK_DOUBLE2("fmax", fmax(1.0, 2.0), "1.0, 2.0", 2.0, 0);
    CHECK_DOUBLE2("fmax", fmax(2.0, 1.0), "2.0, 1.0", 2.0, 0);
