/*
 * test-classify.c -- Accuracy test for classification functions:
 *   finite/finitef, isinf/isinff, isnan/isnanf, fpclassify
 *
 * All results must be exact.
 */
#include "test-common.h"

int main(void)
{
    printf("=== classify accuracy test ===\n");

    /* ---- finite (double) ---- */
    CHECK_BOOL("finite", finite(0.0), "0.0", 1);
    CHECK_BOOL("finite", finite(-0.0), "-0.0", 1);
    CHECK_BOOL("finite", finite(1.0), "1.0", 1);
    CHECK_BOOL("finite", finite(-1.0), "-1.0", 1);
    CHECK_BOOL("finite", finite(5e-324), "5e-324", 1);
    CHECK_BOOL("finite", finite(1e308), "1e308", 1);
    CHECK_BOOL("finite", finite(INFINITY), "Inf", 0);
    CHECK_BOOL("finite", finite(-INFINITY), "-Inf", 0);
    CHECK_BOOL("finite", finite(NAN), "NaN", 0);

    /* ---- finitef (float) ---- */
    CHECK_BOOL("finitef", finitef(0.0f), "0.0f", 1);
    CHECK_BOOL("finitef", finitef(1.0f), "1.0f", 1);
    CHECK_BOOL("finitef", finitef(1.4e-45f), "1.4e-45f", 1);
    CHECK_BOOL("finitef", finitef(INFINITY), "Inf", 0);
    CHECK_BOOL("finitef", finitef(-INFINITY), "-Inf", 0);
    CHECK_BOOL("finitef", finitef(NAN), "NaN", 0);

    /* ---- isinf (double) ---- */
    CHECK_BOOL("isinf", isinf(0.0), "0.0", 0);
    CHECK_BOOL("isinf", isinf(1.0), "1.0", 0);
    CHECK_BOOL("isinf", isinf(INFINITY), "Inf", 1);
    CHECK_BOOL("isinf", isinf(-INFINITY), "-Inf", 1);
    CHECK_BOOL("isinf", isinf(NAN), "NaN", 0);
    CHECK_BOOL("isinf", isinf(5e-324), "5e-324", 0);

    /* ---- isinff (float) ---- */
    CHECK_BOOL("isinff", isinff(0.0f), "0.0f", 0);
    CHECK_BOOL("isinff", isinff(1.0f), "1.0f", 0);
    CHECK_BOOL("isinff", isinff(INFINITY), "Inf", 1);
    CHECK_BOOL("isinff", isinff(-INFINITY), "-Inf", 1);
    CHECK_BOOL("isinff", isinff(NAN), "NaN", 0);

    /* ---- isnan (double) ---- */
    CHECK_BOOL("isnan", isnan(0.0), "0.0", 0);
    CHECK_BOOL("isnan", isnan(1.0), "1.0", 0);
    CHECK_BOOL("isnan", isnan(INFINITY), "Inf", 0);
    CHECK_BOOL("isnan", isnan(-INFINITY), "-Inf", 0);
    CHECK_BOOL("isnan", isnan(NAN), "NaN", 1);
    CHECK_BOOL("isnan", isnan(5e-324), "5e-324", 0);

    /* ---- isnanf (float) ---- */
    CHECK_BOOL("isnanf", isnanf(0.0f), "0.0f", 0);
    CHECK_BOOL("isnanf", isnanf(INFINITY), "Inf", 0);
    CHECK_BOOL("isnanf", isnanf(NAN), "NaN", 1);

    /* ---- fpclassify (double) ---- */
    CHECK_INT("fpclassify", fpclassify(0.0), "0.0", FP_ZERO);
    CHECK_INT("fpclassify", fpclassify(-0.0), "-0.0", FP_ZERO);
    CHECK_INT("fpclassify", fpclassify(1.0), "1.0", FP_NORMAL);
    CHECK_INT("fpclassify", fpclassify(-1.0), "-1.0", FP_NORMAL);
    CHECK_INT("fpclassify", fpclassify(5e-324), "5e-324", FP_SUBNORMAL);
    CHECK_INT("fpclassify", fpclassify(INFINITY), "Inf", FP_INFINITE);
    CHECK_INT("fpclassify", fpclassify(-INFINITY), "-Inf", FP_INFINITE);
    CHECK_INT("fpclassify", fpclassify(NAN), "NaN", FP_NAN);

    /* ---- fpclassify (float) ---- */
    CHECK_INT("fpclassify_f", fpclassify(0.0f), "0.0f", FP_ZERO);
    CHECK_INT("fpclassify_f", fpclassify(1.0f), "1.0f", FP_NORMAL);
    CHECK_INT("fpclassify_f", fpclassify(1.4e-45f), "1.4e-45f", FP_SUBNORMAL);
    CHECK_INT("fpclassify_f", fpclassify(INFINITY), "Inf_f", FP_INFINITE);
    CHECK_INT("fpclassify_f", fpclassify(NAN), "NaN_f", FP_NAN);

    TEST_SUMMARY("classify");
}

