    0.5f, 0.1f, 0.01f,
    2.7182818f, /* e */
    1e-38f, 1e38f,
    1.0000001f, 0.9999999f,
};
#define FIN_COUNT (sizeof(fin)/sizeof(fin[0]))

int main(void)
{
    unsigned i;
    for (i = 0; i < FIN_COUNT; i++)
        P_F1(logf, fin[i]);
    P_F1(logf, 0.0f);
    P_F1(logf, -0.0f);
    P_F1(logf, INFINITY);
    P_F1(logf, -1.0f);
    P_F1(logf, NAN);

    return 0;
}

