/*
 * test-atan.c -- atan() and atanf()
 */
#include "test-common.h"

static const double din[] = {
    0.0, -0.0, 1e-300, -1e-300, 5e-324, 1e-15, -1e-15,
    0.1, 0.5, 1.0, 2.0, 10.0, 100.0, 1e10,
    -0.1, -0.5, -1.0, -2.0, -10.0, -100.0, -1e10,
    /* near 1 */
    0.999999999, 1.000000001,
};
#define DIN_COUNT (sizeof(din)/sizeof(din[0]))

static const float fin[] = {
    0.0f, -0.0f, 1e-38f, 1.4e-45f,
    0.1f, 0.5f, 1.0f, 2.0f, 10.0f, 100.0f, 1e10f,
    -0.1f, -0.5f, -1.0f, -2.0f, -10.0f, -100.0f,
};
#define FIN_COUNT (sizeof(fin)/sizeof(fin[0]))

int main(void)
{
    unsigned i;
    for (i = 0; i < DIN_COUNT; i++)
        P_D1(atan, din[i]);
    P_D1(atan, INFINITY);
    P_D1(atan, -INFINITY);
    P_D1(atan, NAN);

    for (i = 0; i < FIN_COUNT; i++)
        P_F1(atanf, fin[i]);
    P_F1(atanf, INFINITY);
    P_F1(atanf, -INFINITY);
    P_F1(atanf, NAN);

    return 0;
}

